import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { LogIn, Mail, Lock, LogOut, ShieldCheck, FileText, Activity, UserPlus } from 'lucide-react';

const Login = () => {
  const [isRegistering, setIsRegistering] = useState(false); // Switch between Login/Register
  const [formData, setFormData] = useState({ name: '', email: '', password: '' });
  const [message, setMessage] = useState('');
  const [isLoggedIn, setIsLoggedIn] = useState(false);

  useEffect(() => {
    const token = localStorage.getItem('token');
    if (token) setIsLoggedIn(true);
  }, []);

  const handleAuth = async (e) => {
    e.preventDefault();
    const url = isRegistering ? 'register' : 'login';
    try {
      const res = await axios.post(`http://localhost:5000/api/auth/${url}`, formData);
      if (!isRegistering) {
        localStorage.setItem('token', res.data.token);
        localStorage.setItem('userName', res.data.user.name);
        setIsLoggedIn(true);
      } else {
        setMessage('✅ Account created! Please log in.');
        setIsRegistering(false);
      }
    } catch (err) {
      setMessage(err.response?.data?.msg || 'Action Failed');
    }
  };

  const handleLogout = () => {
    localStorage.clear();
    setIsLoggedIn(false);
    setMessage('Logged out successfully.');
  };

  // --- DASHBOARD VIEW ---
  if (isLoggedIn) {
    return (
      <div className="min-h-screen bg-gray-50 p-8">
        <div className="max-w-6xl mx-auto">
          <header className="flex justify-between items-center mb-8 bg-white p-6 rounded-xl shadow-sm border-l-4 border-blue-600">
            <div>
              <h1 className="text-2xl font-bold text-gray-800">QuadSolutions Dashboard</h1>
              <p className="text-gray-500">Welcome back, <span className="font-semibold text-blue-600">{localStorage.getItem('userName')}</span></p>
            </div>
            <button onClick={handleLogout} className="flex items-center text-red-500 font-medium hover:text-red-700">
              <LogOut size={20} className="mr-2" /> Logout
            </button>
          </header>

          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            <div className="bg-white p-6 rounded-xl shadow-sm hover:shadow-md transition cursor-pointer border-b-4 border-blue-400">
              <ShieldCheck className="text-blue-500 mb-4" size={32} />
              <h3 className="font-bold text-lg">Active Licenses</h3>
              <p className="text-3xl font-bold mt-2">04</p>
            </div>
            <div className="bg-white p-6 rounded-xl shadow-sm hover:shadow-md transition cursor-pointer border-b-4 border-green-400">
              <FileText className="text-green-500 mb-4" size={32} />
              <h3 className="font-bold text-lg">Certifications</h3>
              <p className="text-3xl font-bold mt-2">12</p>
            </div>
            <div className="bg-white p-6 rounded-xl shadow-sm hover:shadow-md transition cursor-pointer border-b-4 border-orange-400">
              <Activity className="text-orange-500 mb-4" size={32} />
              <h3 className="font-bold text-lg">Profile Status</h3>
              <p className="text-green-600 font-bold mt-2">92% Complete</p>
            </div>
          </div>
        </div>
      </div>
    );
  }

  // --- LOGIN / REGISTER VIEW ---
  return (
    <div className="flex items-center justify-center min-h-screen bg-gray-100">
      <div className="p-8 bg-white shadow-2xl rounded-2xl w-96 border-t-4 border-blue-600">
        <div className="flex justify-center mb-6 text-blue-600">
          {isRegistering ? <UserPlus size={48} /> : <LogIn size={48} />}
        </div>
        <h2 className="text-2xl font-bold text-center text-gray-800 mb-6">
          {isRegistering ? 'Create Account' : 'QuadSolutions Login'}
        </h2>
        
        <form onSubmit={handleAuth} className="space-y-4">
          {isRegistering && (
            <div className="relative">
              <FileText className="absolute left-3 top-3 text-gray-400" size={20} />
              <input type="text" placeholder="Full Name" className="w-full pl-10 pr-4 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                onChange={(e) => setFormData({...formData, name: e.target.value})} required />
            </div>
          )}
          <div className="relative">
            <Mail className="absolute left-3 top-3 text-gray-400" size={20} />
            <input type="email" placeholder="Email Address" className="w-full pl-10 pr-4 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
              onChange={(e) => setFormData({...formData, email: e.target.value})} required />
          </div>
          <div className="relative">
            <Lock className="absolute left-3 top-3 text-gray-400" size={20} />
            <input type="password" placeholder="Password" className="w-full pl-10 pr-4 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
              onChange={(e) => setFormData({...formData, password: e.target.value})} required />
          </div>
          <button className="w-full bg-blue-600 text-white py-2 rounded-lg font-semibold hover:bg-blue-700">
            {isRegistering ? 'Register Now' : 'Sign In'}
          </button>
        </form>

        <p className="mt-6 text-center text-sm text-gray-600">
          {isRegistering ? "Already have an account?" : "Need an account?"}
          <button onClick={() => setIsRegistering(!isRegistering)} className="ml-2 text-blue-600 font-bold hover:underline">
            {isRegistering ? 'Login here' : 'Register here'}
          </button>
        </p>

        {message && <p className="mt-4 text-center text-sm font-medium text-red-500">{message}</p>}
      </div>
    </div>
  );
};

export default Login;
